from hashlib import md5

def node_for_key(key, nodes, replicas=100):
    # simple consistent-hash lookup (not optimized)
    ring = []
    for n in nodes:
        for i in range(replicas):
            h = int(md5(f"{n}:{i}".encode()).hexdigest(), 16)
            ring.append((h, n))
    ring.sort()
    hkey = int(md5(key.encode()).hexdigest(), 16)
    for h, n in ring:
        if h >= hkey:
            return n
    return ring[0][1]
